let raw=$json.action_input||$json.output||"";
if(!raw)throw new Error("No AI output");
if(typeof raw!=="string")raw=JSON.stringify(raw);
raw=raw.trim();
let p;
try{
  p=JSON.parse(raw);
  if(typeof p==="string")p=JSON.parse(p);
  const n={};
  for(const[k,v]of Object.entries(p))n[k.toLowerCase().trim()]=v;
  p=n;
}catch(e){
  p={};
  for(const l of raw.split("\n").map(s=>s.trim()).filter(s=>s.indexOf("=")>0)){
    const i=l.indexOf("=");
    const k=l.slice(0,i).trim().toLowerCase();
    const v=l.slice(i+1).trim();
    if(k)p[k]=v;
  }
}
const co=String(p.count_only||"").toLowerCase();
p.count_only=co==="true"||co==="1";
const sd=String(p.sitedownflag||"").toLowerCase();
p.sitedownflag=sd.startsWith("yes")?"Yes":"";
const sp=String(p.sitepoweroff||"").toLowerCase();
p.sitepoweroff=sp.startsWith("yes")?"Yes":"";
p.category=String(p.category||"").toUpperCase().trim();
if(!["SITE_DOWN","POWER","CELL_DOWN"].includes(p.category))p.category="";
const vi=["alarm_count","list_alarms","unknown"];
p.intent=vi.includes(String(p.intent||"").toLowerCase())?String(p.intent).toLowerCase():"unknown";
const sr=String(p.severity||"").toLowerCase().trim();
const ks=["critical","major","minor","warning","uncleared","cleared","active","open"];
p.severity=ks.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";
return[{json:p}];

const GEO={"alex":{l:"Alex",o:["ALEX1","ALEX2","ALEX3","ALEX4","AlexCore"]},"alexandria":{l:"Alex",o:["ALEX1","ALEX2","ALEX3","ALEX4","AlexCore"]},"cairo":{l:"Cairo",o:["Cairo","CairoCore","Downtown","Gesr El Suiz","Giza","Helwan","Mohandesen","OSS","Shorouk","Tagamo3"]},"delta":{l:"",o:["DOMYAT","DYARBNEAGM","FAKOUS","MANSURA","ZAGAZIK","DAMANHOUR","DELENGAT","KAFR ELSHEIKH","SHEBIN","TANTA"]},"east delta":{l:"East Delta",o:["DOMYAT","DYARBNEAGM","FAKOUS","MANSURA","ZAGAZIK"]},"west delta":{l:"West Delta",o:["DAMANHOUR","DELENGAT","KAFR ELSHEIKH","SHEBIN","TANTA"]},"upper":{l:"",o:["ASSIUT","BANISUIEF","DEIR MAWAS","FAYOUM","MENYA","Maghagha","ASWAN","Abu simple","EDFO","GERGA","LUXOR","QENA","SOHAG"]},"upper egypt":{l:"",o:["ASSIUT","BANISUIEF","DEIR MAWAS","FAYOUM","MENYA","Maghagha","ASWAN","Abu simple","EDFO","GERGA","LUXOR","QENA","SOHAG"]},"north upper":{l:"North Upper",o:["ASSIUT","BANISUIEF","DEIR MAWAS","FAYOUM","MENYA","Maghagha"]},"south upper":{l:"South Upper",o:["ASWAN","Abu simple","EDFO","GERGA","LUXOR","QENA","SOHAG"]},"sinai":{l:"Sinai",o:["ABO REDIES","ARISH","HURGHADA","ISMAILIA","MARSA ALAM","NUWIBA","RASCEDER","SHARM","SUEZ","ZAFRANA"]}};
const AR={"\u0627\u0633\u0643\u0646\u062f\u0631\u064a\u0629":"alex","\u0627\u0633\u0643\u0646\u062f\u0631\u064a\u0647":"alex","\u0627\u0644\u0642\u0627\u0647\u0631\u0629":"cairo","\u062f\u0644\u062a\u0627":"delta","\u0627\u0644\u0635\u0639\u064a\u062f":"upper","\u0633\u064a\u0646\u0627":"sinai","\u0633\u064a\u0646\u0627\u0621":"sinai"};
const ri=($json.region_input||"").trim();
const key=(AR[ri]||ri).toLowerCase().trim();
const geo=GEO[key]||null;
const location=geo?geo.l:"";
const fm_offices=geo?geo.o:[];
const region_label=geo?(geo.l||key):(ri||"");
return[{json:{intent:$json.intent||"unknown",category:$json.category||"",vendor:$json.vendor||"",location,fm_offices,region_label,networktype:$json.networktype||"",severity:$json.severity||"",sitedownflag:$json.sitedownflag||"",sitepoweroff:$json.sitepoweroff||"",acknowledged:$json.acknowledged||"",sitecode:$json.sitecode||"",count_only:$json.count_only===true||$json.count_only==="true",user_question:$json.user_question||""}}];

const cat=($json.category||"").toUpperCase();
const ven=$json.vendor||"";
const isDirect=cat==="SITE_DOWN"||cat==="POWER"||(cat===""&&ven==="");
let sql;
if(isDirect){
  sql="SELECT '__DIRECT__' AS alarm_name";
}else{
  const w=[];
  if(cat)w.push(`category = '${cat.replace(/'/g,"''")}'`);
  if(ven)w.push(`vendor = '${ven.replace(/'/g,"''")}'`);
  const wc=w.length?`WHERE ${w.join(" AND ")}`:""
  sql=`SELECT alarm_name FROM ai_alarm_mappings ${wc} ORDER BY alarm_name;`.trim();
}
return[{json:{sql,intent:$json.intent,category:$json.category,vendor:$json.vendor,location:$json.location,fm_offices:$json.fm_offices,region_label:$json.region_label,networktype:$json.networktype,severity:$json.severity,sitedownflag:$json.sitedownflag,sitepoweroff:$json.sitepoweroff,acknowledged:$json.acknowledged,sitecode:$json.sitecode,count_only:$json.count_only,user_question:$json.user_question}}];

const ctx=$items("Build SQL")[0].json;
const q=(ctx.user_question||"").toLowerCase();
const now=new Date();
let s=new Date(now),e=new Date(now);
s.setHours(0,0,0,0);e.setHours(23,59,59,999);
if(q.includes("last 1 hour")||q.includes("last hour")){s=new Date(now.getTime()-3600000);e=new Date(now);}
else if(q.includes("last 6 hour")){s=new Date(now.getTime()-21600000);e=new Date(now);}
else if(q.includes("last 12 hour")){s=new Date(now.getTime()-43200000);e=new Date(now);}
else if(q.includes("last 24 hour")){s=new Date(now.getTime()-86400000);e=new Date(now);}
else if(q.includes("yesterday")){s=new Date(now);s.setDate(s.getDate()-1);s.setHours(0,0,0,0);e=new Date(now);e.setDate(e.getDate()-1);e.setHours(23,59,59,999);}
else if(q.includes("last 7 day")){s=new Date(now.getTime()-604800000);e=new Date(now);}
const pad=n=>String(n).padStart(2,"0");
const fmt=d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
let sdf=ctx.sitedownflag||"";let spo=ctx.sitepoweroff||"";
if(ctx.category==="SITE_DOWN"&&!sdf)sdf="Yes";
if(ctx.category==="POWER"&&!spo)spo="Yes";
const alevs=["critical","major","minor","warning"];
const clevs=["uncleared","cleared","active","open"];
const sr=(ctx.severity||"").toLowerCase().trim();
const stdSev=alevs.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";
const clSev=clevs.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";
return[{json:{starttime:s.getTime(),endtime:e.getTime(),start_local:fmt(s),end_local:fmt(e),start:0,limit:100,type:1,intent:ctx.intent,category:ctx.category,vendor:ctx.vendor,location:ctx.location,fm_offices:ctx.fm_offices,region_label:ctx.region_label,networktype:ctx.networktype,standardalarmseverity:stdSev,clearance_severity:clSev,sitedownflag:sdf,sitepoweroff:spo,acknowledged:ctx.acknowledged,sitecode:ctx.sitecode,count_only:ctx.count_only,user_question:ctx.user_question}}];

const alarms=$items("Get Alarm Names From Mapping").map(i=>i.json.alarm_name).filter(Boolean);
const t=$items("Build Time Range")[0].json;
function ne(obj){const r={};for(const[k,v]of Object.entries(obj)){if(v!==null&&v!==undefined&&v!==""&&!(Array.isArray(v)&&v.length===0))r[k]=v;}return r;}
const meta={count_only:t.count_only,user_question:t.user_question,start_local:t.start_local,end_local:t.end_local,location:t.location,fm_offices:t.fm_offices,region_label:t.region_label,vendor:t.vendor,category:t.category,networktype:t.networktype,standardalarmseverity:t.standardalarmseverity,clearance_severity:t.clearance_severity,sitedownflag:t.sitedownflag,sitepoweroff:t.sitepoweroff,acknowledged:t.acknowledged,sitecode:t.sitecode};
const base={start:t.start,limit:t.limit,type:t.type,starttime:t.starttime,endtime:t.endtime};
const filters=ne({location:t.location,sitedownflag:t.sitedownflag,sitepoweroff:t.sitepoweroff,networktype:t.networktype,vendor:t.vendor,standardalarmseverity:t.standardalarmseverity,severity:t.clearance_severity,acknowledged:t.acknowledged,sitecode:t.sitecode});
const isDirect=alarms.length===1&&alarms[0]==="__DIRECT__";
if(isDirect||alarms.length===0){const p=ne({...base,...filters});p._meta=meta;return[{json:p}];}
return alarms.map(alarm=>{const p=ne({...base,alarmname:alarm,...filters});p._meta=meta;return{json:p};});

// Normalize And Post Filter
// NOTE: location filtering is handled by the API via the 'location' header.
// We do NOT re-filter by fm_offices here to avoid double-filtering.
// Post-filters below are for fields the API does NOT filter natively.
const raw = $json;
const t   = $items("Build Time Range")[0].json;
let records = Array.isArray(raw.result) ? raw.result
            : Array.isArray(raw.data)   ? raw.data
            : Array.isArray(raw.rows)   ? raw.rows : [];

// vendor post-filter (API may not support case-insensitive vendor filter)
if (t.vendor)
  records = records.filter(r => (r.vendor || "").toLowerCase() === t.vendor.toLowerCase());

// networktype post-filter
if (t.networktype)
  records = records.filter(r => (r.networktype || "").toLowerCase() === t.networktype.toLowerCase());

// site down / power off flags
if (t.sitedownflag === "Yes")
  records = records.filter(r => r.sitedownflag === "Yes");

if (t.sitepoweroff === "Yes")
  records = records.filter(r => r.sitepoweroff === "Yes");

// acknowledged
if (t.acknowledged)
  records = records.filter(r => (r.acknowledged || "") === t.acknowledged);

// severity (standardalarmseverity = raw severity level: Major, Minor ...)
if (t.standardalarmseverity)
  records = records.filter(r => (r.standardalarmseverity || "").toLowerCase() === t.standardalarmseverity.toLowerCase());

// specific site code
if (t.sitecode)
  records = records.filter(r => (r.sitecode || "") === t.sitecode);

return [{ json: { total: records.length, records } }];

const all = $input.all();
const t = $items("Build Time Range")[0].json;
const co = t.count_only === true;

// unique key for list mode dedup
function uk(r) {
  if (r.alarmid) return "aid_" + r.alarmid;
  if (r.identifierfromprobe) return "ifp_" + r.identifierfromprobe;
  if (r.identifier) return "id_" + r.identifier;

  return "cmp_" + [
    r.sitecode || "",
    r.alarmname || r.rawalarmname || "",
    r.firstoccurrence || "",
    r.networktype || "",
    r.city || r.location || ""
  ].join("_");
}

// collect api totals + unique records
let apiTotal = 0;
const seen = new Set();
const unique = [];

for (const item of all) {
  const itemTotal = Number(item.json.total || 0);
  apiTotal += itemTotal;

  for (const r of (item.json.records || [])) {
    const k = uk(r);
    if (!seen.has(k)) {
      seen.add(k);
      unique.push(r);
    }
  }
}

const dedupedTotal = unique.length;

// for count queries: use API total
// for list queries: use deduped unique count
const finalTotal = co ? apiTotal : dedupedTotal;

// group for list mode
const groups = {};
for (const r of unique) {
  const n = r.alarmname || r.rawalarmname || "Unknown";
  groups[n] = (groups[n] || 0) + 1;
}

// filter summary
const parts = [];
if (t.region_label) parts.push("Location : " + t.region_label);
if (t.category) parts.push("Category : " + t.category);
if (t.sitedownflag === "Yes") parts.push("SiteDown : Yes");
if (t.sitepoweroff === "Yes") parts.push("PowerOff : Yes");
if (t.vendor) parts.push("Vendor   : " + t.vendor);
if (t.networktype) parts.push("Network  : " + t.networktype);
if (t.acknowledged) parts.push("Acked    : " + t.acknowledged);
if (t.standardalarmseverity) parts.push("Severity : " + t.standardalarmseverity);
if (t.sitecode) parts.push("SiteCode : " + t.sitecode);

const sep = "─".repeat(48);

let reply = `📡 NOC Report — ${t.start_local} → ${t.end_local}\n${sep}\nTotal : ${finalTotal}\n`;

if (parts.length) {
  reply += `Filters:\n  ${parts.join("\n  ")}\n`;
}

reply += sep;

// list mode only
if (!co && Object.keys(groups).length) {
  reply += "\n\nBreakdown:";
  const sorted = Object.entries(groups).sort((a, b) => b[1] - a[1]);
  for (const [n, c] of sorted) {
    reply += `\n  • ${n} : ${c}`;
  }
}

if (!co && unique.length) {
  const top = Math.min(10, unique.length);
  reply += `\n\nTop ${top} Sites:`;
  for (let i = 0; i < top; i++) {
    const r = unique[i];
    reply += `\n  ${i + 1}. ${r.sitecode || r.sitename || "?"} — ${r.networktype || "?"} — ${r.vendor || "?"} — ${r.city || r.location || "?"}`;
  }
  if (dedupedTotal > 10) {
    reply += `\n  ... and ${dedupedTotal - 10} more`;
  }
}

return [{
  json: {
    reply,
    total: finalTotal,
    api_total: apiTotal,
    deduped_total: dedupedTotal,
    groups
  }
}];

// ══════════════════════════════════════════════════
// DEBUG FULL CONTEXT — NOC AI Agent V3.1
// ══════════════════════════════════════════════════

// ── Raw inputs from each node ──
const chatIn  = $items("When chat message received")[0]?.json?.chatInput || "";
const aiRaw   = $items("AI Agent")[0]?.json?.output || "";
const parsed  = $items("Parse Agent Output")[0]?.json || {};
const loc     = $items("Resolve Location")[0].json;
const sql     = $items("Build SQL")[0].json.sql;
const mapping = $items("Get Alarm Names From Mapping").map(i => i.json.alarm_name);
const t       = $items("Build Time Range")[0].json;
const payloads = $items("Build API Payload").map(i => { const p = {...i.json}; delete p._meta; return p; });
const normSummary = $items("Normalize And Post Filter").map(i => ({
  records_after_filter: i.json.total,
  sample: (i.json.records || []).slice(0, 2).map(r => ({
    sitecode: r.sitecode,
    city: r.city,
    networktype: r.networktype,
    alarmname: r.alarmname || r.rawalarmname,
    sitedownflag: r.sitedownflag,
    severity: r.rawseverity
  }))
}));
const finalReply = $json.reply || "";
const deduped    = $json.total || 0;
const apiTotal   = $json.api_total || 0;

// ══════════════════════════════════════════════════
// SECTION 1 — Question & AI Understanding
// ══════════════════════════════════════════════════
const section1 = {
  original_question : chatIn,
  ai_raw_output     : String(aiRaw).slice(0, 300),
  what_AI_understood: {
    intent      : parsed.intent       || "(empty)",
    category    : parsed.category     || "(empty)",
    vendor      : parsed.vendor       || "(empty)",
    region_input: parsed.region_input || "(empty)",
    networktype : parsed.networktype  || "(empty)",
    severity    : parsed.severity     || "(empty)",
    sitedownflag: parsed.sitedownflag || "(empty)",
    sitepoweroff: parsed.sitepoweroff || "(empty)",
    sitecode    : parsed.sitecode     || "(empty)",
    count_only  : parsed.count_only
  }
};

// ══════════════════════════════════════════════════
// SECTION 2 — Parameters Sent to API
// ══════════════════════════════════════════════════
const firstPayload = payloads[0] || {};
const section2 = {
  location_resolved: {
    location    : loc.location     || "(empty)",
    region_label: loc.region_label || "(empty)",
    fm_offices  : loc.fm_offices   || []
  },
  alarm_mapping: {
    sql_used      : sql,
    alarms_found  : mapping
  },
  time_range: {
    start_local: t.start_local,
    end_local  : t.end_local,
    starttime  : t.starttime,
    endtime    : t.endtime
  },
  api_headers_sent: {
    start                : firstPayload.start ?? 0,
    limit                : firstPayload.limit ?? 100,
    type                 : firstPayload.type  ?? 1,
    starttime            : firstPayload.starttime,
    endtime              : firstPayload.endtime,
    alarmname            : firstPayload.alarmname            || "(empty)",
    location             : firstPayload.location             || "(empty)",
    sitedownflag         : firstPayload.sitedownflag         || "(empty)",
    sitepoweroff         : firstPayload.sitepoweroff         || "(empty)",
    networktype          : firstPayload.networktype          || "(empty)",
    vendor               : firstPayload.vendor               || "(empty)",
    standardalarmseverity: firstPayload.standardalarmseverity|| "(empty)",
    severity             : firstPayload.severity             || "(empty)",
    acknowledged         : firstPayload.acknowledged         || "(empty)"
  },
  total_api_calls: payloads.length
};

// ══════════════════════════════════════════════════
// SECTION 3 — Results
// ══════════════════════════════════════════════════
const section3 = {
  total_from_api        : apiTotal,
  total_after_dedup     : deduped,
  api_response_summary  : normSummary,
  final_reply           : finalReply
};

// ── Return structured debug ──
return [{
  json: {
    "[1] Question & AI Understanding": section1,
    "[2] Parameters Sent to API"     : section2,
    "[3] Results"                    : section3
  }
}];
